-- Ken's Hardened V2 Fix

local b64_0xlllIll = {}
local char_0xIlIIl1='ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
for i_0xIlIII1=1,#char_0xIlIIl1 do b64_0xlllIll[char_0xIlIIl1:sub(i_0xIlIII1,i_0xIlIII1)] = i_0xIlIII1 - 1 end

function b64_0xlllIll.dec_0x1Il1II(d_0xlI11Il)
    d_0xlI11Il = string.gsub(d_0xlI11Il, '[^'..char_0xIlIIl1..'=]', '')
    local r_0xl1lIll = {}
    for i_0xIlIII1=1, #d_0xlI11Il, 4 do
        local c_0xl1I1ll = b64_0xlllIll[d_0xlI11Il:sub(i_0xIlIII1,i_0xIlIII1)] or 0
        local c_0x111lll = b64_0xlllIll[d_0xlI11Il:sub(i_0xIlIII1+1,i_0xIlIII1+1)] or 0
        local c_0xlIllII, c_0xllllII = 0, 0
        local has3 = true
        local has4 = true
        local ch3 = d_0xlI11Il:sub(i_0xIlIII1+2,i_0xIlIII1+2)
        if ch3 == "=" then has3 = false else c_0xlIllII = b64_0xlllIll[ch3] or 0 end
        local ch4 = d_0xlI11Il:sub(i_0xIlIII1+3,i_0xIlIII1+3)
        if ch4 == "=" then has4 = false else c_0xllllII = b64_0xlllIll[ch4] or 0 end
        local b_0xIIIllI = c_0xl1I1ll * (2^18) + c_0x111lll * (2^12) + c_0xlIllII * (2^6) + c_0xllllII
        local b_0xlIIlII = math.floor(b_0xIIIllI / (2^16)) % (2^8)
        local b_0xlI1III = math.floor(b_0xIIIllI / (2^8)) % (2^8)
        local b_0xIIl111 = b_0xIIIllI % (2^8)
        table.insert(r_0xl1lIll, string.char(b_0xlIIlII))
        if has3 then table.insert(r_0xl1lIll, string.char(b_0xlI1III)) end
        if has4 then table.insert(r_0xl1lIll, string.char(b_0xIIl111)) end
    end
    return table.concat(r_0xl1lIll)
end


local function bxor_0xllll1l(a_0x11llI1,b_0xlllI1I)
    if bit32 then return bit32.bxor(a_0x11llI1,b_0xlllI1I) end
    local r_0x1IIIlI = 0
    for i_0xII1I11 = 0, 7 do
        local x_0xI1l1lI = a_0x11llI1 % 2
        local y_0x1lII1I = b_0xlllI1I % 2
        if x_0xI1l1lI ~= y_0x1lII1I then r_0x1IIIlI = r_0x1IIIlI + (2^i_0xII1I11) end
        a_0x11llI1 = math.floor(a_0x11llI1 / 2)
        b_0xlllI1I = math.floor(b_0xlllI1I / 2)
    end
    return r_0x1IIIlI
end


local function bxor_str_0xlI1lII(s_0xIl1II1, k_0x1lIIIl)
    local r_0xl1Illl = {}
    for i_0x1lIlIl=1, #s_0xIl1II1 do
        local b_0x1llllI = string.byte(s_0xIl1II1, i_0x1lIlIl)
        local kb_0xl1IIII = string.byte(k_0x1lIIIl, (i_0x1lIlIl-1) % #k_0x1lIIIl + 1)
        r_0xl1Illl[i_0x1lIlIl] = string.char(bxor_0xllll1l(b_0x1llllI, kb_0xl1IIII))
    end
    return table.concat(r_0xl1Illl)
end


local function getkeys_0xIIlI1I()
    local seed = b64_0xlllIll.dec_0x1Il1II("M3FrdGt3eFU=")
    local k1_enc = b64_0xlllIll.dec_0x1Il1II("eT9aRwYVCy0=")
    local k2_enc = b64_0xlllIll.dec_0x1Il1II("ajAPGSodGgI=")
    return bxor_str_0xlI1lII(k1_enc, seed), bxor_str_0xlI1lII(k2_enc, seed)
end


local function cff_0x1l1III(a_0xI1llII)
    local st_0xlll1ll = 0
    local res_0xII111I = a_0xI1llII
    while true do
        if st_0xlll1ll == 0 then
            res_0xII111I = res_0xII111I + 1
            st_0xlll1ll = 1
        elseif st_0xlll1ll == 1 then
            res_0xII111I = res_0xII111I * 2
            st_0xlll1ll = 2
        elseif st_0xlll1ll == 2 then
            res_0xII111I = res_0xII111I - 3
            st_0xlll1ll = 3
        else
            break
        end
    end
    return res_0xII111I
end


local function chain_0xlllII1(x) return x*2 end
local function chain_0xIll1Il(x) return chain_0xlllII1(x)+1 end


local d_0xIIlllI = {
  {op=255, val="", is_enc=true},
}
local pc_0xII1l1l = 1
local stk_0xIIllll = {}
stk_0xIIllll._jmp = nil


local disp_0xlIIllI = {
    [0] = function() end,
    [1] = function(s, v) table.insert(s, v) end,
    [2] = function(s, v) table.insert(s, _G[v]) end,
    [3] = function(s, v) local val=table.remove(s); _G[v]=val end,
    [4] = function(s, _) table.insert(s, {}) end,
    [5] = function(s, _) local val=table.remove(s); local key=table.remove(s); local t=table.remove(s); t[key]=val; table.insert(s, t) end,
    [16] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a+b) end,
    [17] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a-b) end,
    [18] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a*b) end,
    [19] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a/b) end,
    [32] = function(s, n) 
        local args = {}
        for i=1,tonumber(n) do table.insert(args, 1, table.remove(s)) end
        local f = table.remove(s)
        if type(f) == "function" then
            local result = {f(unpack(args))}
            for _,v in ipairs(result) do table.insert(s, v) end
        else
            print("[LBI] Not a function: "..tostring(f))
        end
    end,
    [33] = function(s) return table.remove(s) end,
    [48] = function(s, offset) 
        local cond = table.remove(s)
        if not cond then 
            s._jmp = tonumber(offset)
        end
    end,
    [49] = function(s, offset)
        s._jmp = tonumber(offset)
    end,
    [255] = function(s, v)
        local fn, err = loadstring(v)
        if not fn then
            print("[LBI] Load error: "..tostring(err))
        else
            local ok, res = pcall(fn)
            if not ok then print("[LBI] Run error: "..tostring(res)) end
        end
    end
}



local k1, k2 = getkeys_0xIIlI1I()

local state_0xIlIl1I = 0
while true do
    if state_0xIlIl1I == 0 then  -- FETCH
        if pc_0xII1l1l > #d_0xIIlllI then break end
        local inst = d_0xIIlllI[pc_0xII1l1l]
        local opcode = inst.op
        local val = inst.val
        if inst.is_enc then
            local d = b64_0xlllIll.dec_0x1Il1II(val)
            d = bxor_str_0xlI1lII(d, k2)
            val = bxor_str_0xlI1lII(d, k1)
        end
        stk_0xIIllll._jmp = nil
        pc_0xII1l1l = pc_0xII1l1l + 1
        cur_op_0xIIIlll = opcode
        cur_val_0xI11lI1 = val
        state_0xIlIl1I = 1

    elseif state_0xIlIl1I == 1 then  -- EXECUTE
        local handler = disp_0xlIIllI[cur_op_0xIIIlll]
        if handler then
            handler(stk_0xIIllll, cur_val_0xI11lI1)
        end
        if stk_0xIIllll._jmp then
            pc_0xII1l1l = pc_0xII1l1l + stk_0xIIllll._jmp
        end
        state_0xIlIl1I = 0
    else
        break
    end
end
